using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public class WeatherTools
{
    private readonly HttpClient _httpClient;

    // The MCP SDK creates an instance per invocation for instance methods.
    // Constructor parameters are resolved from the DI container automatically.
    public WeatherTools(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [McpServerTool(Name = "get_weather")]
    [Description("Gets the current weather for a city using the Open-Meteo API.")]
    public async Task<string> GetWeatherAsync(
        [Description("City latitude (e.g. 47.6062 for Seattle)")] double latitude,
        [Description("City longitude (e.g. -122.3321 for Seattle)")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.open-meteo.com/v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        var response = await _httpClient.GetFromJsonAsync<WeatherResponse>(url, cancellationToken);

        if (response?.Current is null)
            return "No weather data available for the given coordinates.";

        return $"Temperature: {response.Current.Temperature}°C, "
             + $"Wind speed: {response.Current.WindSpeed} km/h";
    }

    [McpServerTool(Name = "get_forecast")]
    [Description("Gets a multi-day weather forecast for a location.")]
    public async Task<string> GetForecastAsync(
        [Description("City latitude")] double latitude,
        [Description("City longitude")] double longitude,
        [Description("Number of forecast days (1-7, default 3)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        days = Math.Clamp(days, 1, 7);

        var url = $"https://api.open-meteo.com/v1/forecast?latitude={latitude}&longitude={longitude}"
                + $"&daily=temperature_2m_max,temperature_2m_min&forecast_days={days}";

        var response = await _httpClient.GetFromJsonAsync<ForecastResponse>(url, cancellationToken);

        if (response?.Daily is null)
            return "No forecast data available.";

        var lines = new List<string>();
        for (int i = 0; i < response.Daily.Time.Count; i++)
        {
            lines.Add($"{response.Daily.Time[i]}: "
                     + $"High {response.Daily.MaxTemp[i]}°C, "
                     + $"Low {response.Daily.MinTemp[i]}°C");
        }

        return string.Join('\n', lines);
    }
}

// --- JSON models for Open-Meteo API ---

public record WeatherResponse(
    [property: JsonPropertyName("current")] CurrentWeather? Current);

public record CurrentWeather(
    [property: JsonPropertyName("temperature_2m")] double Temperature,
    [property: JsonPropertyName("wind_speed_10m")] double WindSpeed);

public record ForecastResponse(
    [property: JsonPropertyName("daily")] DailyForecast? Daily);

public record DailyForecast(
    [property: JsonPropertyName("time")] List<string> Time,
    [property: JsonPropertyName("temperature_2m_max")] List<double> MaxTemp,
    [property: JsonPropertyName("temperature_2m_min")] List<double> MinTemp);

