+    public async Task<string> GetForecastAsync(
+        [Description("City latitude")] double latitude,
+        [Description("City longitude")] double longitude,
+        [Description("Number of forecast days (1-7, default 3)")] int days = 3,
+        CancellationToken cancellationToken = default)
+    {
+        days = Math.Clamp(days, 1, 7);
+
+        var url = $"https://api.open-meteo.com/v1/forecast?latitude={latitude}&longitude={longitude}"
+                + $"&daily=temperature_2m_max,temperature_2m_min&forecast_days={days}";
+
+        var response = await _httpClient.GetFromJsonAsync<ForecastResponse>(url, cancellationToken);
+
+        if (response?.Daily is null)
+            return "No forecast data available.";
+
+        var lines = new List<string>();
+        for (int i = 0; i < response.Daily.Time.Count; i++)
+        {
+            lines.Add($"{response.Daily.Time[i]}: "
+                     + $"High {response.Daily.MaxTemp[i]}°C, "
+                     + $"Low {response.Daily.MinTemp[i]}°C");
+        }
+
+        return string.Join('\n', lines);
+    }
+}
